package com.example.documentviewer;

import android.content.ContentResolver;
import android.content.Intent;
import android.database.Cursor;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.provider.OpenableColumns;
import android.view.View;
import android.view.ViewGroup;
import android.widget.FrameLayout;
import android.widget.ImageView;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.io.FileNotFoundException;
import java.io.IOException;

public class DocumentViewActivity extends AppCompatActivity {

    private FrameLayout root;
    private TextView messageView;
    private ImageView imageView;

    private ParcelFileDescriptor pdfPfd;
    private PdfRenderer pdfRenderer;
    private PdfRenderer.Page currentPage;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        root = new FrameLayout(this);
        root.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));

        imageView = new ImageView(this);
        imageView.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        imageView.setVisibility(View.GONE);

        messageView = new TextView(this);
        messageView.setLayoutParams(new FrameLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        ));
        int pad = dp(16);
        messageView.setPadding(pad, pad, pad, pad);

        root.addView(imageView);
        root.addView(messageView);

        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(@Nullable Intent intent) {
        closePdf();

        if (intent == null) {
            showMessage("No intent.");
            return;
        }

        String action = intent.getAction();
        Uri data = intent.getData();

        if (!Intent.ACTION_VIEW.equals(action) || data == null) {
            showMessage("Unsupported intent.");
            return;
        }

        String mime = intent.getType();
        if (mime == null) mime = getContentResolver().getType(data);

        if (mime == null) {
            String name = getDisplayName(data);
            if (name != null) {
                String lower = name.toLowerCase();
                if (lower.endsWith(".pdf")) mime = "application/pdf";
                else if (lower.endsWith(".png")) mime = "image/png";
                else if (lower.endsWith(".jpg") || lower.endsWith(".jpeg")) mime = "image/jpeg";
                else if (lower.endsWith(".webp")) mime = "image/webp";
                else if (lower.endsWith(".gif")) mime = "image/gif";
                else if (lower.endsWith(".bmp")) mime = "image/bmp";
                else if (lower.endsWith(".heic") || lower.endsWith(".heif")) mime = "image/heic";
            }
        }

        if (mime != null && mime.equals("application/pdf")) {
            renderPdfFirstPage(data);
        } else if (mime != null && mime.startsWith("image/")) {
            renderImage(data);
        } else {
            showMessage("Unsupported file type: " + (mime == null ? "unknown" : mime));
        }
    }

    private void renderImage(Uri uri) {
        try {
            ContentResolver cr = getContentResolver();
            Bitmap bm = BitmapFactory.decodeStream(cr.openInputStream(uri));
            if (bm == null) {
                showMessage("Unable to decode image.");
                return;
            }
            imageView.setImageBitmap(bm);
            imageView.setVisibility(View.VISIBLE);
            messageView.setText("");
        } catch (FileNotFoundException e) {
            showMessage("File not found.");
        }
    }

    private void renderPdfFirstPage(Uri uri) {
        try {
            pdfPfd = getContentResolver().openFileDescriptor(uri, "r");
            if (pdfPfd == null) {
                showMessage("Unable to open PDF.");
                return;
            }

            pdfRenderer = new PdfRenderer(pdfPfd);
            if (pdfRenderer.getPageCount() <= 0) {
                showMessage("Empty PDF.");
                return;
            }

            currentPage = pdfRenderer.openPage(0);
            int width = currentPage.getWidth();
            int height = currentPage.getHeight();

            Bitmap bitmap = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888);
            currentPage.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);

            imageView.setImageBitmap(bitmap);
            imageView.setVisibility(View.VISIBLE);
            messageView.setText("");
        } catch (SecurityException e) {
            showMessage("No permission to read this file.");
        } catch (IOException e) {
            showMessage("Unable to render PDF.");
        }
    }

    private void showMessage(String msg) {
        imageView.setImageDrawable(null);
        imageView.setVisibility(View.GONE);
        messageView.setText(msg);
    }

    private String getDisplayName(Uri uri) {
        if (!"content".equalsIgnoreCase(uri.getScheme())) return null;
        Cursor c = null;
        try {
            c = getContentResolver().query(uri, new String[]{OpenableColumns.DISPLAY_NAME}, null, null, null);
            if (c != null && c.moveToFirst()) return c.getString(0);
        } catch (Exception ignored) {
        } finally {
            if (c != null) c.close();
        }
        return null;
    }

    private int dp(int v) {
        float d = getResources().getDisplayMetrics().density;
        return Math.round(v * d);
    }

    private void closePdf() {
        try {
            if (currentPage != null) currentPage.close();
        } catch (Exception ignored) {
        }
        currentPage = null;

        try {
            if (pdfRenderer != null) pdfRenderer.close();
        } catch (Exception ignored) {
        }
        pdfRenderer = null;

        try {
            if (pdfPfd != null) pdfPfd.close();
        } catch (Exception ignored) {
        }
        pdfPfd = null;
    }

    @Override
    protected void onDestroy() {
        closePdf();
        super.onDestroy();
    }
}


